/**
 * widgetDrafts — pure I/O for ~/Library/Application Support/dash/Dashboard/widget-drafts.json
 *
 * Stores in-progress widgets generated by the AI Builder. Each draft
 * holds enough state to fully restore the modal: the chat history, the
 * latest generated component + config code, the picked provider, and
 * any remix/edit-mode context. A draft is created on the first
 * parseable AI response, updated on every subsequent response in the
 * same session, and deleted when the user successfully installs the
 * widget (or explicitly deletes the draft from the list).
 *
 * Atomicity: writes go through a tmp file + rename. A crash mid-save
 * leaves the previous drafts.json intact rather than a half-truncated
 * file the next session can't parse.
 *
 * Resilience: a corrupt JSON file does NOT throw — listDrafts() and
 * getDraft() return [] / null and leave the file in place. The next
 * saveDraft() call will overwrite it. This keeps a bad write from
 * permanently breaking the AI Builder.
 *
 * No electron deps here so the module is testable from node:test
 * with a tmpdir.
 */
"use strict";

const fs = require("fs");
const path = require("path");
const os = require("os");

const SCHEMA_VERSION = 1;

let resolvedDraftsFilePath = null;
let testOverridePath = null;

/**
 * Test-only: pin the drafts file to a specific path. Pass null to
 * clear and fall back to the production resolver.
 */
function _setDraftsFilePathForTest(p) {
    testOverridePath = p;
    resolvedDraftsFilePath = null;
}

/**
 * Where the drafts JSON lives. Mirrors the workspaces.json convention:
 * <userData>/Dashboard/widget-drafts.json. Resolved lazily so we don't
 * import electron eagerly (this module is also exercised under
 * node:test with no electron environment).
 */
function getDraftsFilePath() {
    if (testOverridePath) return testOverridePath;
    if (resolvedDraftsFilePath) return resolvedDraftsFilePath;
    let userData;
    try {
        // electron.app — only available in the main process at runtime
        const electron = require("electron");
        userData = electron?.app?.getPath?.("userData");
    } catch (_) {
        userData = null;
    }
    if (!userData) {
        // Fallback for non-electron contexts (shouldn't happen in
        // production — main process always has electron). Use a
        // platform-appropriate path so dev tinkering doesn't write
        // into cwd.
        userData = path.join(os.homedir(), ".dash");
    }
    resolvedDraftsFilePath = path.join(
        userData,
        "Dashboard",
        "widget-drafts.json"
    );
    return resolvedDraftsFilePath;
}

function readRaw() {
    const file = getDraftsFilePath();
    let text;
    try {
        text = fs.readFileSync(file, "utf8");
    } catch (err) {
        if (err.code === "ENOENT") return { drafts: [] };
        // Other I/O errors — surface as empty so the UI keeps working.
        return { drafts: [] };
    }
    try {
        const parsed = JSON.parse(text);
        if (parsed && Array.isArray(parsed.drafts)) return parsed;
        return { drafts: [] };
    } catch (_) {
        // Corrupt file. Don't throw — let the next save overwrite it.
        return { drafts: [] };
    }
}

function writeRaw(payload) {
    const file = getDraftsFilePath();
    const dir = path.dirname(file);
    fs.mkdirSync(dir, { recursive: true });
    const tmp = `${file}.${process.pid}.${Date.now()}.tmp`;
    fs.writeFileSync(tmp, JSON.stringify(payload, null, 2), "utf8");
    fs.renameSync(tmp, file);
}

function listDrafts() {
    const { drafts } = readRaw();
    // Newest first. Falsy updatedAt sorts last.
    return [...drafts].sort((a, b) => (b.updatedAt || 0) - (a.updatedAt || 0));
}

function getDraft(id) {
    if (!id) return null;
    const { drafts } = readRaw();
    return drafts.find((d) => d.id === id) || null;
}

/**
 * Insert a new draft or update an existing one in place. Caller
 * supplies `id`. createdAt is preserved on update; updatedAt is bumped
 * on every save. Unknown fields on the input are persisted as-is so
 * the schema can grow without code changes here.
 */
function saveDraft(draft) {
    if (!draft || typeof draft !== "object" || !draft.id) {
        throw new Error("saveDraft requires a draft with an id");
    }
    const { drafts } = readRaw();
    const now = Date.now();
    const idx = drafts.findIndex((d) => d.id === draft.id);
    const merged = {
        ...(idx >= 0 ? drafts[idx] : {}),
        ...draft,
        createdAt: idx >= 0 ? drafts[idx].createdAt : now,
        updatedAt: now,
        schemaVersion: SCHEMA_VERSION,
    };
    if (idx >= 0) drafts[idx] = merged;
    else drafts.push(merged);
    writeRaw({ drafts });
    return merged;
}

function deleteDraft(id) {
    if (!id) return;
    const { drafts } = readRaw();
    const filtered = drafts.filter((d) => d.id !== id);
    if (filtered.length === drafts.length) return; // no-op
    writeRaw({ drafts: filtered });
}

module.exports = {
    listDrafts,
    getDraft,
    saveDraft,
    deleteDraft,
    getDraftsFilePath,
    SCHEMA_VERSION,
    _setDraftsFilePathForTest,
};
